import org.owasp.encoder.Encode;

public class XSSFixedCode {
    public static void main(String[] args) {
        // Simulating user input, which could come from a web form
        String userInput = "<script>alert('XSS attack!')</script>";

        // Properly handling user input by escaping it before including it in the HTML response
        String safeUserInput = Encode.forHtml(userInput);

        // Creating a safe HTML response to prevent XSS vulnerability
        String safeHtmlResponse = "<p>Welcome, " + safeUserInput + "</p>";

        // Printing the safe HTML response
        System.out.println(safeHtmlResponse);
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
